import { expect, test } from '@playwright/test';
import { loadProjectConfig } from './fixtures/project-config';

const config = loadProjectConfig();
const isForthAMS = config.project.name.toLowerCase() === 'forthams';
const API_BASE = config.project.apiBaseUrl || 'http://localhost:8080';

test.describe('forthAMS 全量路由自发现', () => {
  test.setTimeout(180000);
  let healthOk = false;

  test.beforeAll(async ({ request }) => {
    if (!isForthAMS) return;
    const r = await request.get(`${API_BASE}/health`, { timeout: 5000 }).catch(() => null);
    healthOk = r?.status() === 200;
  });

  test('导航爬取 → 全量路由 + 深层表单页 + 按钮探索检测', async ({ page }) => {
    test.skip(!isForthAMS);
    test.skip(!healthOk);

    const apiErrors: { method: string; path: string; status: number }[] = [];
    const reactCrashes: string[] = [];
    const visitedUrls = new Set<string>();
    let pass = 0, fail = 0;

    page.on('response', (res) => {
      const p = new URL(res.url()).pathname;
      if (p.startsWith('/api') && res.status() >= 400)
        apiErrors.push({ method: res.request().method(), path: p, status: res.status() });
    });
    page.on('pageerror', (e) => reactCrashes.push(e.message.slice(0, 200)));

    // 辅助函数：访问页面并检测错误
    async function visitAndCheck(href: string, source = ''): Promise<boolean> {
      if (visitedUrls.has(href)) return true;
      visitedUrls.add(href);

      const pa = apiErrors.length, pr = reactCrashes.length;
      await page.goto(href, { waitUntil: 'networkidle', timeout: 15000 }).catch(() => {});
      await page.waitForTimeout(1000);

      const newApi = apiErrors.slice(pa), newReact = reactCrashes.slice(pr);
      const bodyLen = await page.evaluate(() => document.body?.innerText?.length || 0).catch(() => 0);
      const ok = newApi.length === 0 && newReact.length === 0 && bodyLen >= 5 && !page.url().includes('/login');

      const label = source ? `${href} (${source})` : href;
      if (ok) {
        console.log(`  \u2713 ${label}`);
        pass++;
      } else {
        const reason = newReact[0] || (newApi[0] ? `API ${newApi[0].status} ${newApi[0].path}` : (bodyLen < 5 ? '空白页' : '重定向'));
        console.log(`  \u2717 ${label} \u2192 ${reason}`);
        fail++;
      }
      return ok;
    }

    // ==================== 登录 ====================
    await page.goto('/login', { waitUntil: 'domcontentloaded' });
    await page.locator('#username').fill('admin');
    await page.locator('#password').fill('admin123');
    await page.locator('button[type="submit"]').click();
    await page.waitForTimeout(2000);
    expect(await page.evaluate(() => sessionStorage.getItem('auth_token') || localStorage.getItem('auth_token'))).toBeTruthy();
    // 清空登录过程中的错误记录
    apiErrors.length = 0;
    reactCrashes.length = 0;

    // ===== 阶段1: 爬取导航链接并访问 =====
    const navLinks: string[] = await page.evaluate(() => {
      const seen = new Set<string>();
      document.querySelectorAll('nav a[href], aside a[href]').forEach(a => {
        const h = (a as HTMLAnchorElement).getAttribute('href');
        if (h && h.startsWith('/') && !h.startsWith('/login') && h !== '/') seen.add(h);
      });
      return [...seen];
    });
    console.log(`  阶段1: 发现 ${navLinks.length} 个导航路由`);

    for (const href of ['/', ...navLinks]) {
      await visitAndCheck(href, '导航');
    }

    // ===== 阶段2: 直接访问已知深层路由 =====
    const deepRoutes: string[] = [
      '/assets/new',
      '/inventory/tasks',
      '/disposals/transfer/new',
      '/disposals/clearance/new',
      '/disposals/scrap/new',
      '/disposals/compensation/new',
      '/vendors/new',
      '/locations/new',
      '/locations/tree',
      '/retirement',
      '/retirement/new',
      '/workorders/new',
      '/categories',
      '/workflow-designer',
    ];
    console.log(`\n  阶段2: 深层路由 ${deepRoutes.length} 个`);
    for (const route of deepRoutes) {
      await visitAndCheck(route, '深层路由');
    }

    // ===== 阶段3: 按钮点击探索深层表单页 =====
    console.log(`\n  阶段3: 按钮点击探索`);
    for (const href of [...visitedUrls]) {
      await page.goto(href, { waitUntil: 'networkidle', timeout: 15000 }).catch(() => {});
      await page.waitForTimeout(1000);

      const buttons = await page.locator('button, a[role="button"], [class*="btn" i], [class*="Button" i]')
        .filter({ hasText: /新建|新增|添加|创建/ })
        .all();

      for (const btn of buttons) {
        const text = await btn.textContent().catch(() => '');
        if (!text?.trim()) continue;

        const pa2 = apiErrors.length, pr2 = reactCrashes.length;
        const beforeUrl = page.url();

        await Promise.all([
          page.waitForURL(url => {
            return url.pathname !== new URL(beforeUrl).pathname && !url.pathname.includes('/login');
          }, { timeout: 10000 }).catch(() => {}),
          btn.click().catch(() => {}),
        ]);
        await page.waitForTimeout(1000);

        const currentPath = new URL(page.url()).pathname;
        if (visitedUrls.has(currentPath) || currentPath === new URL(beforeUrl).pathname) continue;

        visitedUrls.add(currentPath);
        const newApi2 = apiErrors.slice(pa2), newReact2 = reactCrashes.slice(pr2);
        const bodyLen2 = await page.evaluate(() => document.body?.innerText?.length || 0).catch(() => 0);
        const ok2 = newApi2.length === 0 && newReact2.length === 0 && bodyLen2 >= 5;

        const label2 = `${currentPath} (按钮: "${text.trim()}" @ ${href})`;
        if (ok2) {
          console.log(`  \u2713 ${label2}`);
          pass++;
        } else {
          const reason2 = newReact2[0] || (newApi2[0] ? `API ${newApi2[0].status} ${newApi2[0].path}` : (bodyLen2 < 5 ? '空白页' : ''));
          console.log(`  \u2717 ${label2} \u2192 ${reason2}`);
          fail++;
        }
      }
    }

    // ===== 阶段4: 资产处置页面 Tab 切换探索 =====
    console.log(`\n  阶段4: Tab 切换探索`);
    if (visitedUrls.has('/disposals')) {
      await page.goto('/disposals', { waitUntil: 'networkidle', timeout: 15000 }).catch(() => {});
      await page.waitForTimeout(1000);

      const tabs = await page.locator('[role="tab"], [class*="tab" i], button:has([class*="tab" i])').all();
      for (const tab of tabs) {
        const tabText = await tab.textContent().catch(() => '');
        if (!tabText?.trim()) continue;

        const pa3 = apiErrors.length, pr3 = reactCrashes.length;
        await tab.click().catch(() => {});
        await page.waitForTimeout(1000);

        const newApi3 = apiErrors.slice(pa3), newReact3 = reactCrashes.slice(pr3);
        if (newApi3.length > 0 || newReact3.length > 0) {
          console.log(`  \u26A0 /disposals Tab "${tabText.trim()}" \u2192 ${newApi3.length > 0 ? `API ${newApi3[0].status} ${newApi3[0].path}` : newReact3[0]}`);
        } else {
          console.log(`  \u2713 /disposals Tab "${tabText.trim()}" OK`);
        }
      }
    }

    // ===== 汇总输出 =====
    console.log(`\n  ===== 最终结果 =====`);
    console.log(`  访问页面: ${visitedUrls.size}, 通过: ${pass}, 失败: ${fail}`);
    if (apiErrors.length) {
      console.log(`\n  API 错误汇总:`);
      const seen = new Set<string>();
      for (const e of apiErrors) {
        const k = `${e.method} ${e.path} ${e.status}`;
        if (!seen.has(k)) { seen.add(k); console.log(`    ${k}`); }
      }
    }
    if (reactCrashes.length) {
      console.log(`\n  React 崩溃:`);
      const seen = new Set<string>();
      for (const c of reactCrashes) { if (!seen.has(c)) { seen.add(c); console.log(`    ${c}`); } }
    }

    expect(reactCrashes).toEqual([]);
    expect(fail).toBe(0);
  });
});
